    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'models'::text)), ARRAY[]::uuid[]) AS model_ids,
    COALESCE(array_agg(DISTINCT l.resource_id) FILTER (WHERE (l.resource_type = 'names'::text)), ARRAY[]::uuid[]) AS name_ids,
